import { defineAgent } from "eve";

export default defineAgent({
  model: process.env.AGENT_MODEL ?? "anthropic/claude-sonnet-4.6",
  description:
    "Runs browser-driven QA on web app flows such as signup and onboarding, captures evidence, and returns concise Markdown reports."
});

import { defineSandbox } from "eve/sandbox";

export default defineSandbox({
  async bootstrap({ use }) {
    const sandbox = await use();
    await sandbox.run({
      command: "bash setup-agent-browser.sh"
    });
  },
  async onSession({ use }) {
    const sandbox = await use();
    await sandbox.run({
      command: "bash setup-agent-browser.sh"
    });
  }
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 1,
  timeoutMs: 120_000
});

export const websiteQaSmokePrompt = [
  "Test https://example.com.",
  "",
  "Goal: smoke-test the public homepage only. Do not sign up, submit forms, use payment, bypass CAPTCHA, or use credentials.",
  "First run bash setup-agent-browser.sh. Then use Agent Browser in the sandbox to open the page, inspect a snapshot, and capture one screenshot under reports/assets/example-home.png.",
  "Return a concise Markdown QA report. If browser automation is unavailable, report that blocker clearly instead of doing a static HTML or SEO audit."
].join("\n");

export const requiredReportSectionPatterns = [
  /Executive Summary/i,
  /What Was Checked/i,
  /Findings/i,
  /Screenshots?\s*\/?\s*Artifacts?/i,
  /Recommended Fixes/i,
  /Follow[- ]Up Test Prompt/i
] as const;

export const agentBrowserCommandPattern = /agent-browser/;

import { defineEval } from "eve/evals";
import { includes } from "eve/evals/expect";
import {
  agentBrowserCommandPattern,
  requiredReportSectionPatterns,
  websiteQaSmokePrompt
} from "../shared/website-qa-smoke.js";

export default defineEval({
  description:
    "Verifies the Website QA agent uses browser automation and returns the expected Markdown report shape.",
  tags: ["smoke", "website-qa"],
  async test(t) {
    await t.send(websiteQaSmokePrompt);

    t.completed();
    t.noFailedActions();
    t.calledTool("bash", { input: { command: agentBrowserCommandPattern } });
    t.check(t.reply, includes("example.com"));

    for (const section of requiredReportSectionPatterns) {
      t.messageIncludes(section);
    }
  }
});
